INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00109', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡透氧率（oxygenpermeability,Dk）與傳氧率（oxygentransmissibility,Dk/t）之敘述，下列何者 錯誤？', '["軟式水膠隱形眼鏡透氧率會隨溫度升高而產生變化", "軟式水膠隱形眼鏡傳氧率與鏡片的厚度有關", "日戴型隱形眼鏡（dailywear,DW）至少需要透氧率 24 以上", "軟式水膠隱形眼鏡，遠視鏡片（+3.00D）會比近視鏡片（-3.00D）的傳氧率低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00110', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '對於軟式隱形眼鏡材質而言，下列敘述何者正確？', '["通常折射率與含水量成正比", "高彈性係數（modulusofelasticity）的材質抵抗鏡片形變的能力較高", "親水性佳的材質有較高的DK值，且較不易有沉積物", "根據FDA的分類，第三類及第四類建議不要使用熱消毒法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00111', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關懸滴法（sessiledroptechniques）測量水膠隱形眼鏡材質的接觸角，下列那一個接觸角的材質親水性最佳？', '["30", "50", "80", "100"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00112', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列那一種彈性模數（modulus of elasticity）之矽水膠隱形眼鏡最容易造成上方上皮弧形損傷（superior epithelialarcuatelesions）以及巨乳突狀結膜炎（giantpapillaryconjunctivitis）？', '["1.40MPA", "1.10MPA", "0.75MPA", "0.35MPA"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00113', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡的清潔，下列敘述何者正確？', '["只有沖洗鏡片就可以完全清除黏附在鏡片的污染物", "軟式隱形眼鏡的清潔，除了沖洗之外再加上清潔劑搓洗，能使鏡片上的污染物減少至<300cfu", "每週清潔鏡片少於兩次與每週清潔兩次以上的隱形眼鏡配戴者相比較，兩者之間鏡片的污染風險無差異", "使用隱形眼鏡溶液進行搓洗與沖洗清潔鏡片，與單獨用溶液沖洗鏡片相較，兩種方式的清潔程度相同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00114', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡清潔藥水Polyhexanide（聚鹽酸己雙胍聚六亞甲基雙胍，PHMB）與 Chlorhexidine（洗 必泰）之敘述何者錯誤？', '["大多數的多功能護理液內若含有PHMB，最初是作為術前抗菌清潔擦洗劑而研發", "PHMB與Chlorhexidine屬於相同的藥物科，對大多數細菌均有活性", "PHMB的作用，在細菌細胞表面能快速吸引帶負電的磷脂，因鉀離子的損失和細胞內成分的沉澱而將細胞 膜的活性破壞", "PHMB的分子量比Chlorhexidine小，所以它可以進入軟式隱形眼鏡材料的基質內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00115', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡護理液中的螯合劑（chelatingagents），例如乙二胺四乙酸（EDTA），常用來加強苯甲醯氯（benzoyl chloride,BzCl）的那一種作用？', '["濕潤劑", "防腐劑", "黏稠劑", "潤滑劑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00116', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '多功能藥水裡的防腐劑中，關於減少毒性及超敏反應，聚己酰胺（polyhexanide）和聚季銨鹽（polyquad） 與氯己定（chlorhexidine）和硫柳汞（thiomersal）保存系統相比，下列敘述何者正確？', '["因為氯己定具有比聚六亞甲基雙胍和聚季銨鹽，更大的分子量", "因為聚六亞甲基雙胍和聚季銨鹽具有比氯己定更大的分子量，並且它們比鏡片孔的尺寸更大。這降低了 防腐劑到達眼表面的可能性", "因為聚六亞甲基雙胍和聚季銨鹽具有親水性質", "因為聚六亞甲基雙胍吸引正離子"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00117', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列關於隱形眼鏡患者教育和衛生，下列何者正確？', '["有特殊情況時，配戴者才需要配戴目前使用的隱形眼鏡前來就診", "患者之非醫囑性（noncompliance）和缺乏知識是隱形眼鏡併發症的主要原因，這可能是患者缺乏關注或 醫生不重視患者教育的結果", "當配戴者感覺有症狀或不舒服時，才需要進行追蹤照護，否則不用複檢", "追蹤照護檢查之流程不包含視力檢查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00118', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '當驗配硬式隱形眼鏡角膜散光大於2D時，下列敘述何者錯誤？', '["出現順散的角膜散光，螢光劑會匯集在垂直子午線", "在眨眼過程中鏡片的「搖擺」可能導致眼睛不舒服", "較容易出現機械性角膜染色", "建議選擇較高透氧性的材料，會比較舒服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
